    19→// NewPaaSAPIServerCommand creates a *cobra.Command object with default parameters
    20→func NewPaaSAPIServerCommand() *cobra.Command {
    21→	o := options.NewOptions()
    22→
    23→	if err := loadConfig(o); err != nil {
    24→		fmt.Fprintf(os.Stderr, "error loading config file: %v\n", err)
    25→	}
    26→
    27→	cmd := &cobra.Command{
    28→		Use:  "paas-apiserver",
    29→		Long: "The paas-apiserver is a proxy api server of kubernetes",
    30→		// stop printing usage when the command errors
    31→		SilenceUsage: true,
    32→		PreRunE: func(cmd *cobra.Command, args []string) error {
    33→			//setup zap log
    34→			sync := o.Log.Complete().SetUp()
    35→			//register zap log sync to stoppers
    36→			if err := signal.RegisterStopper("log", sync); err != nil {
    37→				log.Error(err)
    38→				return err
    39→			}
    40→			return nil
    41→		},
    42→		RunE: func(cmd *cobra.Command, args []string) error {
    43→			if errs := o.Validate(); len(errs) != 0 {
    44→				return errs.ToAggregate()
    45→			}
    46→			if o.Generic.Version {
    47→				return version.PrintVersion()
    48→			}
    49→			return run(cmd, o, signal.SetupSignalHandler().Done())
    50→		},
    51→		Args: func(cmd *cobra.Command, args []string) error {
    52→			for _, arg := range args {
    53→				if len(arg) > 0 {
    54→					return fmt.Errorf("%q does not take any arguments, got %q", cmd.CommandPath(), args)
    55→				}
    56→			}
    57→			return nil
    58→		},
    59→	}
    60→
    61→	nfs := &cliflag.NamedFlagSets{}
    62→	o.AddFlags(nfs)
    63→	fs := cmd.Flags()
    64→	for _, f := range nfs.FlagSets {
    65→		fs.AddFlagSet(f)
    66→	}
    67→	cols, _, _ := term.TerminalSize(cmd.OutOrStdout())
    68→	cliflag.SetUsageAndHelpFunc(cmd, *nfs, cols)
    69→
    70→	return cmd
    71→}
    72→func run(cmd *cobra.Command, o *options.Options, stopCh <-chan struct{}) error {
    73→	ctx, cancel := context.WithCancel(context.Background())
    74→	go func() {
    75→		<-stopCh
    76→		cancel()
    77→	}()
    78→
    79→	serverConfig := o.APIServer.Complete()
    80→	esClient, err := o.ES.Complete().NewClient()
    81→	if err != nil {
    82→		return err
    83→	}
    84→	if o.ES.Address != "" {
    85→		err = esClient.CheckHealth()
    86→		if err != nil {
    87→			log.Errorf("check es health failed %v", err)
    88→		}
    89→	} else {
    90→		log.Info("es address is empty, use default config")
    91→	}
    92→
    93→	aiClient, err := o.Chat.Complete().NewAiClient()
    94→	if err != nil {
    95→		log.Error(err)
    96→	}
    97→
    98→	// register server to backend
    99→	registerConfig := o.Register.Complete()
   100→	registerConfig.AddAuthInfo(o.APIServer.AuthenticationMode, o.APIServer.BasicAccounts)
   101→	registerConfig.AddKubeconfig(o.APIServer.KubeConfigPath)
   102→	registrar, err := registerConfig.New()
   103→	if err != nil {
   104→		log.Error(err)
   105→		return err
   106→	}
   107→	err = registrar.Register()
   108→	if err != nil {
   109→		log.Error(err)
   110→		return err
   111→	}
   112→	// register DeregisterBackend func to stoppers
   113→	if err = signal.RegisterStopper("deregister-apiserver", func() error {
   114→		return registrar.Deregister()
   115→	}); err != nil {
   116→		log.Error(err)
   117→		return err
   118→	}
   119→
   120→	server, err := serverConfig.NewAPIServer(esClient, aiClient)
   121→	if err != nil {
   122→		log.Error(err)
   123→		return err
   124→	}
   125→	// register api-server stop func to stoppers
   126→	if err = signal.RegisterStopper("api-server", server.Stopper); err != nil {
   127→		log.Error(err)
   128→		return err
   129→	}
   130→	// register api-server handlers
   131→	server.RegisterHandlers()
   132→	// run api-server
   133→	return server.Run(ctx)
   134→
   135→}
   136→
   137→func loadConfig(o *options.Options) error {
   138→	viper.SetConfigName("paas-apiserver")
   139→	viper.SetConfigType("yaml")
   140→	viper.AddConfigPath("/etc/paas-controller")
   141→	viper.AddConfigPath(".")
   142→	err := viper.ReadInConfig()
   143→	if err != nil {
   144→		fmt.Fprintf(os.Stderr, "error reading config file: %v\n", err)
   145→		return err
   146→	}
   147→
   148→	if err := viper.Unmarshal(o); err != nil {
   149→		fmt.Fprintf(os.Stderr, "error unmarshalling config file: %v\n", err)
   150→		return err
   151→	}
   152→
   153→	return nil
   154→}
